const Product = require("../model/Products-schema"); // Import your Product schema
const CreateNewProduct = async (req, res) => {
  try {
    const { name, description, price, stockCount, categoryId, images } =
      req.body;
    console.log(req.body);
    // This path is the secure HTTPS URL generated by Cloudinary
    const imageUrl = req.file.path;

    // Create the new product using the schema we built earlier
    const newProduct = new Product({
      name: name,
      description: description,
      price: price,
      categoryId: categoryId,
      stockCount: stockCount,
      images: imageUrl, // Save the secure Cloudinary string URL to MongoDB array
    });

    await newProduct.save();

    return res
      .status(200)
      .json({ message: "Product created successfully", data: newProduct });
  } catch (err) {
    return res.status(500).json({ message: err.message });
  }
};

module.exports = {
  CreateNewProduct,
};
